import{o,c as n,ae as i,j as t,n as s,p as l}from"./chunks/framework.DfCsusKa.js";const h={class:"language-toggle-wrapper"},d={class:"language-toggle-bar"},m=JSON.parse('{"title":"霍爾木茲海峽新秩序：伊朗強推通行申報，企圖鞏固關鍵航道掌控權 | Iran Imposes New Rules for Hormuz to Cement Control","description":"伊朗針對通過霍爾木茲海峽的船隻強推全新通行申報制度。本文深入剖析此地緣政治博弈中的三大看點以及對全球能源的深遠影響。","frontmatter":{"title":"霍爾木茲海峽新秩序：伊朗強推通行申報，企圖鞏固關鍵航道掌控權 | Iran Imposes New Rules for Hormuz to Cement Control","description":"伊朗針對通過霍爾木茲海峽的船隻強推全新通行申報制度。本文深入剖析此地緣政治博弈中的三大看點以及對全球能源的深遠影響。"},"headers":[],"relativePath":"news/iran-imposes-new-rules-strait-of-hormuz.md","filePath":"news/iran-imposes-new-rules-strait-of-hormuz.md"}'),p={name:"news/iran-imposes-new-rules-strait-of-hormuz.md"},f=Object.assign(p,{setup(c){const a=l("bilingual");return(u,e)=>(o(),n("div",null,[e[4]||(e[4]=i('<h1 id="伊朗強推霍爾木茲海峽新新規-企圖全面掌控關鍵黃金航道-iran-imposes-new-rules-for-hormuz-in-effort-to-cement-control-of-key-waterway" tabindex="-1">伊朗強推霍爾木茲海峽新新規：企圖全面掌控關鍵黃金航道 <br><span style="font-size:1.5rem;color:var(--vp-c-text-2);">Iran Imposes New Rules for Hormuz in Effort to Cement Control of Key Waterway</span> <a class="header-anchor" href="#伊朗強推霍爾木茲海峽新新規-企圖全面掌控關鍵黃金航道-iran-imposes-new-rules-for-hormuz-in-effort-to-cement-control-of-key-waterway" aria-label="Permalink to &quot;伊朗強推霍爾木茲海峽新新規：企圖全面掌控關鍵黃金航道 &lt;br&gt;&lt;span style=&quot;font-size: 1.5rem; color: var(--vp-c-text-2);&quot;&gt;Iran Imposes New Rules for Hormuz in Effort to Cement Control of Key Waterway&lt;/span&gt;&quot;">​</a></h1><div style="text-align:center;margin:24px 0 32px 0;"><img src="https://media.cnn.com/api/v1/images/stellar/prod/gettyimages-2273981246.jpg?c=16x9&amp;q=w_800,c_fill" alt="Strait of Hormuz" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div>',2)),t("div",h,[t("div",d,[t("button",{class:s(["language-toggle-btn",{active:a.value==="bilingual"}]),onClick:e[0]||(e[0]=r=>a.value="bilingual")},"中英雙語",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="zh"}]),onClick:e[1]||(e[1]=r=>a.value="zh")},"純中文",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="en"}]),onClick:e[2]||(e[2]=r=>a.value="en")},"純英文",2)])]),t("div",{class:s(["bilingual-article","mode-"+a.value])},[...e[3]||(e[3]=[i('<div class="bilingual-paragraph"><p class="zh-text">伊朗正試圖強迫航運業者遵守通過霍爾木茲海峽（Strait of Hormuz）的全新協議，否則將面臨遭受襲擊的風險。根據 CNN 取得的一份文件，德黑蘭已為試圖通過該海峽的船隻制定了一套新規則，在無視美國警告的情況下，執意推動該水道控制權的正式化。</p><p class="en-text">Iran is trying to force shippers to comply with a new protocol for transiting the Strait of Hormuz — or risk attack. Tehran has laid out a set of new rules for vessels seeking to transit the strait, according to a document seen by CNN, pressing ahead with efforts to formalize control over the waterway in defiance of US warnings.</p></div><div class="bilingual-paragraph"><p class="zh-text">這份名為「船隻信息申報」（Vessel Information Declaration）的文件，是由伊朗新成立的「波斯灣海峽管理局」（PGSA）發布的申請表，所有過境船隻必須填寫以確保安全通行。該文件由 Lloyd&#39;s List 和另一位不願透露姓名的航運業消息人士與 CNN 分享。</p><p class="en-text">Entitled “Vessel Information Declaration,” the document is an application form issued by Iran’s newly created Persian Gulf Strait Authority (PGSA) and must be completed by all transiting vessels to ensure safe passage. It was shared with CNN by Lloyds List and another shipping industry source who wished to remain anonymous.</p></div><div class="bilingual-paragraph"><p class="zh-text">在美國和以色列於二月底發動針對伊朗的軍事行動之前，任何國籍的船隻都可以自由航行於該海峽。但自衝突爆發以來，伊朗威脅將襲擊任何在未獲得伊斯蘭革命衛隊（IRGC）海軍許可的情況下通過霍爾木茲海峽的船隻。儘管已有數艘船隻遭到襲擊，但絕大多數船東和運營商已選擇不冒險強行通過。</p><p class="en-text">Before the US and Israeli campaign against Iran began at the end of February, the strait was free for any vessel of any origin to navigate. But since the conflict began, Iran has threatened to strike any ship passing through Hormuz without permission from the Islamic Revolutionary Guard Corps (IRGC) navy. A number of vessels have come under attack, but the vast majority of ship owners and operators have opted not to take the risk of sending their vessels through in defiance of Iran.</p></div><div class="bilingual-paragraph"><p class="zh-text">設立該海峽管理機構的舉動，凸顯了伊朗鞏固對該水道控制權的決心（伊朗將其視為「戰爭掠奪品」），儘管美國和地區盟友一再發出警告。霍爾木茲海峽承載了全球五分之一的石油和液化天然氣，控制這一黃金航道將使伊朗對鄰國及全球經濟擁有巨大的地緣政治槓桿。</p><p class="en-text">The move to set up an authority for the strait underscores Iran’s determination to cement control over what it sees as a spoil of war, despite repeated US and regional warnings. Dominance of the waterway, through which one-fifth of the world’s oil and liquefied natural gas flows, would hand the Islamic Republic immense leverage over its neighbors and the global economy.</p></div><div class="bilingual-paragraph"><p class="zh-text">霍爾木茲海峽的實際封鎖引發了歷史上最大的石油供應衝擊，導致能源價格急劇飆升。本週三，美國汽油價格四年來首次突破每加侖 4.50 美元，對全球通膨與供應鏈投下了震撼彈。</p><p class="en-text">The closure of the Strait of Hormuz unleashed the biggest oil supply shock in history, sending energy prices sharply higher. On Wednesday, US gas prices rose above $4.50 per gallon for the first time in four years.</p></div><hr><h2 id="🔍-海峽新協議三大核心看點-three-key-highlights-of-the-new-waterway-protocol" tabindex="-1">🔍 海峽新協議三大核心看點 <br><span style="font-size:1.2rem;color:var(--vp-c-text-2);">Three Key Highlights of the New Waterway Protocol</span> <a class="header-anchor" href="#🔍-海峽新協議三大核心看點-three-key-highlights-of-the-new-waterway-protocol" aria-label="Permalink to &quot;🔍 海峽新協議三大核心看點 &lt;br&gt;&lt;span style=&quot;font-size: 1.2rem; color: var(--vp-c-text-2);&quot;&gt;Three Key Highlights of the New Waterway Protocol&lt;/span&gt;&quot;">​</a></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">1. 超過 40 項細節的「船隻申報表」</h3><span class="dish-card-badge">Takeaway 1</span></div><div class="bilingual-paragraph"><p class="zh-text">目前向航運商提供的 PGSA 申報文件包含 40 多個問題，要求船隻申報船名、識別號碼、任何「曾用名」、出發國與目的地。它還要求提供註冊船東、營運商以及船上船員的國籍，以及貨物的詳細資訊。不準確或不完整的資訊將由申請人承擔全部責任。</p><p class="en-text">The PGSA document now made available to shippers comprises more than 40 questions, requiring vessels to declare their name and identification number, any “previous name,” country of origin and destination. It also asks for the nationalities of the registered owners and operators and of the crew on board, plus details of the cargo. Any incorrect or incomplete information will be the sole responsibility of the applicant.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">2. 巨額航道通行費與制裁風險</h3><span class="dish-card-badge">Takeaway 2</span></div><div class="bilingual-paragraph"><p class="zh-text">目前尚不清楚通行是否需要付費，但德黑蘭已將該海峽宣傳為潛在的收入來源，可用於重建因美以襲擊而受損的基礎設施。據報導，伊朗對每艘過境船隻收取高達 200 萬美元的通行費。然而，美國財政部警告稱，向伊朗政府或革命衛隊支付此類費用將使美國個人或金融機構面臨嚴厲制裁。</p><p class="en-text">It’s unclear from the document whether passage will incur a fee. Tehran has touted the strait as a potential revenue stream that could help rebuild the country after destruction caused by American and Israeli strikes. It is reportedly charging up to $2 million per vessel for passage. However, the US Treasury clarified that such payments to the Iranian government or IRGC would not be authorized and would violate sanctions.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">3. 上萬名無辜船員深陷地緣夾縫</h3><span class="dish-card-badge">Takeaway 3</span></div><div class="bilingual-paragraph"><p class="zh-text">夾在地緣博弈中間的，是波斯灣內近 1,000 艘被困船隻上的多達 20,000 名船員。他們的生存條件非常艱苦，承受著這場擴大為地區衝突的所有後果。海事專家強調：「海員不是士兵，他們是管理全球貿易的平民，不應該被捲入這樣的地緣衝突中。」</p><p class="en-text">Caught in the middle are as many as 20,000 seafarers on nearly 1,000 vessels trapped in the Persian Gulf, with their crews in very difficult conditions, bearing all the consequences of a war that is expanding. Maritime experts emphasize: “Mariners are not soldiers. They are civilians managing global trade. They should not be caught in a situation like this.”</p></div></div>',10)])],2)]))}});export{m as __pageData,f as default};
